import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';

const WS_BASE = window.location.protocol === 'https:' ? 'wss://' : 'ws://';
const WS_HOST = window.location.host;

const Icon = ({ name, size = 16 }) => {
  const icons = {
    chat: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>,
    x: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>,
    send: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>,
    phone: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"/></svg>,
    phoneOff: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10.68 13.31a16 16 0 0 0 3.41 2.6l1.27-1.27a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.42 19.42 0 0 1-3.33-2.67"/><line x1="1" y1="1" x2="23" y2="23"/></svg>,
    mic: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>,
    image: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>,
    user: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>,
    shield: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>,
    play: <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor"><polygon points="5 3 19 12 5 21 5 3"/></svg>,
    pause: <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>,
    check: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>,
  };
  return icons[name] || null;
};

const WAVEFORM_BARS = [3,5,8,4,7,10,6,3,8,5,9,4,7,3,6,8,5,10,4,7,6,3,8,5];

const AudioPlayer = ({ src, dark }) => {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  useEffect(() => {
    const a = audioRef.current;
    if (!a) return;
    const onMeta = () => setDuration(a.duration || 0);
    const onTime = () => setCurrentTime(a.currentTime || 0);
    const onEnd = () => { setPlaying(false); setCurrentTime(0); };
    a.addEventListener('loadedmetadata', onMeta);
    a.addEventListener('timeupdate', onTime);
    a.addEventListener('ended', onEnd);
    return () => { a.removeEventListener('loadedmetadata', onMeta); a.removeEventListener('timeupdate', onTime); a.removeEventListener('ended', onEnd); };
  }, []);

  const toggle = () => {
    if (!audioRef.current) return;
    if (playing) audioRef.current.pause(); else audioRef.current.play();
    setPlaying(!playing);
  };
  const fmtT = (s) => { const m = Math.floor(s/60); return `${m}:${Math.floor(s%60).toString().padStart(2,'0')}`; };
  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;

  const barActive = dark ? 'bg-white/80' : 'bg-purple-600/80';
  const barInactive = dark ? 'bg-white/30' : 'bg-gray-300';
  const textCls = dark ? 'opacity-70' : 'text-gray-500';
  const btnCls = dark ? 'bg-white/20 hover:bg-white/30' : 'bg-gray-200 hover:bg-gray-300';

  return (
    <div className="flex items-center gap-2 py-1 min-w-[170px]">
      <audio ref={audioRef} src={src} preload="metadata" />
      <button onClick={toggle} className={`w-8 h-8 rounded-full ${btnCls} flex items-center justify-center flex-shrink-0`}>
        {playing ? <Icon name="pause" size={12} /> : <Icon name="play" size={12} />}
      </button>
      <div className="flex-1 flex flex-col gap-0.5">
        <div className="flex items-end gap-[2px] h-[20px]">
          {WAVEFORM_BARS.map((h, i) => (
            <div key={i} className={`w-[3px] rounded-full transition-colors ${(i / WAVEFORM_BARS.length) * 100 <= progress ? barActive : barInactive}`} style={{ height: `${h * 2}px` }} />
          ))}
        </div>
        <div className={`flex justify-between text-[9px] ${textCls}`}>
          <span>{fmtT(playing ? currentTime : 0)}</span>
          <span>{duration > 0 ? fmtT(duration) : '--:--'}</span>
        </div>
      </div>
    </div>
  );
};

const SeenIndicator = ({ sent }) => (
  <span className="inline-flex ml-1 opacity-60">
    {sent ? (
      <span className="flex -space-x-1.5"><Icon name="check" size={10} /><Icon name="check" size={10} /></span>
    ) : (
      <Icon name="check" size={10} />
    )}
  </span>
);

const ChatWidget = () => {
  const [open, setOpen] = useState(false);
  const [view, setView] = useState('form');
  const [sessaoId, setSessaoId] = useState(null);
  const [protocolo, setProtocolo] = useState('');
  const [mensagens, setMensagens] = useState([]);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [p2pEnabled, setP2pEnabled] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [cliente, setCliente] = useState(null);
  const [verificationCode, setVerificationCode] = useState('');
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '' });

  // P2P
  const [incomingCall, setIncomingCall] = useState(false);
  const [callOffer, setCallOffer] = useState(null);
  const [inCall, setInCall] = useState(false);
  const [callDuration, setCallDuration] = useState(0);
  const callTimerRef = useRef(null);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);
  const remoteAudioRef = useRef(null);
  const pendingIceCandidatesRef = useRef([]);
  const remoteDescSetRef = useRef(false);

  // Audio recording
  const [isRecordingAudio, setIsRecordingAudio] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const mediaRecorderRef = useRef(null);
  const recordedChunksRef = useRef([]);
  const recordingTimerRef = useRef(null);

  const wsRef = useRef(null);
  const messagesEndRef = useRef(null);
  const imageInputRef = useRef(null);
  const [unread, setUnread] = useState(0);

  const [wsConnected, setWsConnected] = useState(false);
  const wsReconnectRef = useRef(null);
  const wsSidRef = useRef(null);

  // ── WebSocket with auto-reconnect ──
  const connectWS = useCallback((sid) => {
    wsSidRef.current = sid;
    if (wsRef.current) { try { wsRef.current.close(); } catch(e){} }
    clearTimeout(wsReconnectRef.current);
    const url = `${WS_BASE}${WS_HOST}/ws/chat/cliente/${sid}`;
    console.log('[ChatWS] Connecting:', url);
    const ws = new WebSocket(url);
    wsRef.current = ws;
    ws.onopen = () => { console.log('[ChatWS] Connected'); setWsConnected(true); };
    ws.onmessage = (evt) => {
      try {
        const data = JSON.parse(evt.data);
        console.log('[ChatWS] Received:', data.type);
        if (data.type === 'nova_mensagem') {
          setMensagens(prev => [...prev, data]);
          if (!open) setUnread(prev => prev + 1);
        }
        if (data.type === 'sessao_encerrada') {
          setMensagens(prev => [...prev, { remetente: 'sistema', mensagem: 'Sessão encerrada pelo atendente.' }]);
        }
        if (data.type === 'protocolo') {
          setProtocolo(data.protocolo);
          setMensagens(prev => [...prev, { remetente: 'sistema', mensagem: data.mensagem || `Protocolo: ${data.protocolo}` }]);
        }
        if (data.type === 'webrtc_offer') {
          console.log('[ChatWS] Incoming call offer received!');
          setIncomingCall(true);
          setCallOffer(data);
        }
        if (data.type === 'webrtc_answer' || data.type === 'webrtc_ice') handleWebRTCSignal(data);
      } catch (e) { console.error('[ChatWS] Message error:', e); }
    };
    ws.onerror = (e) => { console.error('[ChatWS] Error:', e); };
    ws.onclose = (e) => {
      console.log('[ChatWS] Disconnected, code:', e.code);
      setWsConnected(false);
      if (wsSidRef.current) {
        wsReconnectRef.current = setTimeout(() => {
          console.log('[ChatWS] Reconnecting...');
          connectWS(wsSidRef.current);
        }, 2000);
      }
    };
  }, [open]);

  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [mensagens]);

  // ── Auth handlers ──
  const handleSendVerification = async (e) => {
    e.preventDefault();
    if (!formData.email) { setError('Digite seu email'); return; }
    setLoading(true); setError('');
    try {
      await axios.post('/api/verification/send', { email: formData.email, tipo: 'chat' });
      setView('verify');
    } catch (err) { setError(err.response?.data?.detail || 'Erro ao enviar código'); }
    finally { setLoading(false); }
  };

  const handleResendCode = async () => {
    setLoading(true); setError('');
    try {
      await axios.post('/api/verification/resend', { email: formData.email, tipo: 'chat' });
      alert('Novo código enviado! Verifique sua caixa de entrada e spam.');
    } catch (err) { setError(err.response?.data?.detail || 'Erro ao reenviar código'); }
    finally { setLoading(false); }
  };

  const handleRegister = async (e) => {
    e.preventDefault(); setLoading(true); setError('');
    try {
      const res = await axios.post('/api/chat/register', { ...formData, codigo: verificationCode });
      setSessaoId(res.data.sessao_id); setProtocolo(res.data.protocolo);
      setCliente(res.data.cliente); setMensagens(res.data.mensagens || []);
      setP2pEnabled(res.data.p2p_enabled); setView('chat'); connectWS(res.data.sessao_id);
    } catch (err) { setError(err.response?.data?.detail || 'Erro ao criar conta'); }
    finally { setLoading(false); }
  };

  const handleLogin = async (e) => {
    e.preventDefault(); setLoading(true); setError('');
    try {
      const res = await axios.post('/api/chat/login', { email: formData.email, senha: formData.senha });
      setSessaoId(res.data.sessao_id); setProtocolo(res.data.protocolo);
      setCliente(res.data.cliente); setMensagens(res.data.mensagens || []);
      setP2pEnabled(res.data.p2p_enabled); setView('chat'); connectWS(res.data.sessao_id);
    } catch (err) { setError(err.response?.data?.detail || 'Erro ao fazer login'); }
    finally { setLoading(false); }
  };

  // ── Messages ──
  const handleEnviar = async (e) => {
    e.preventDefault();
    if (!novaMensagem.trim() || !sessaoId) return;
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: 'mensagem', mensagem: novaMensagem }));
      setMensagens(prev => [...prev, { remetente: 'cliente', mensagem: novaMensagem, data_criacao: new Date().toISOString() }]);
      setNovaMensagem('');
    } else {
      try {
        await axios.post('/api/chat/mensagem', { sessao_id: sessaoId, mensagem: novaMensagem });
        setMensagens(prev => [...prev, { remetente: 'cliente', mensagem: novaMensagem, data_criacao: new Date().toISOString() }]);
        setNovaMensagem('');
      } catch (err) { setError('Erro ao enviar mensagem'); }
    }
  };

  // ── Image upload ──
  const handleImageUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file || !sessaoId) return;
    const formDataUpload = new FormData();
    formDataUpload.append('file', file);
    try {
      const res = await axios.post(`/api/chat/imagem/${sessaoId}`, formDataUpload, { headers: { 'Content-Type': 'multipart/form-data' } });
      setMensagens(prev => [...prev, { remetente: 'cliente', mensagem: '📷 Imagem', data_criacao: new Date().toISOString(), extra: { tipo: 'imagem', arquivo: res.data.arquivo } }]);
    } catch (err) { alert('Erro ao enviar imagem: ' + (err.response?.data?.detail || 'Erro')); }
    e.target.value = '';
  };

  // ── Audio recording (WhatsApp-style) ──
  const startAudioRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      recordedChunksRef.current = [];
      const mr = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mr.ondataavailable = (e) => { if (e.data.size > 0) recordedChunksRef.current.push(e.data); };
      mr.onstop = () => { stream.getTracks().forEach(t => t.stop()); };
      mr.start();
      mediaRecorderRef.current = mr;
      setIsRecordingAudio(true);
      setRecordingTime(0);
      recordingTimerRef.current = setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) { alert('Erro ao acessar microfone: ' + err.message); }
  };

  const cancelAudioRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
    }
    clearInterval(recordingTimerRef.current);
    setIsRecordingAudio(false);
    setRecordingTime(0);
    recordedChunksRef.current = [];
  };

  const sendAudioRecording = async () => {
    if (!mediaRecorderRef.current || mediaRecorderRef.current.state === 'inactive') return;
    mediaRecorderRef.current.stop();
    clearInterval(recordingTimerRef.current);
    setIsRecordingAudio(false);
    setRecordingTime(0);

    await new Promise(r => setTimeout(r, 300));
    if (recordedChunksRef.current.length === 0 || !sessaoId) return;

    const blob = new Blob(recordedChunksRef.current, { type: 'audio/webm' });
    const formDataUpload = new FormData();
    formDataUpload.append('file', blob, 'audio.webm');
    try {
      const res = await axios.post(`/api/chat/audio/${sessaoId}`, formDataUpload, { headers: { 'Content-Type': 'multipart/form-data' } });
      setMensagens(prev => [...prev, { remetente: 'cliente', mensagem: '🎤 Áudio', data_criacao: new Date().toISOString(), extra: { tipo: 'audio', arquivo: res.data.arquivo } }]);
    } catch (err) { alert('Erro ao enviar áudio'); }
  };

  const formatTime = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  // ── WebRTC (client only receives calls from admin) ──
  const handleWebRTCSignal = (data) => {
    if (data.type === 'webrtc_ice') {
      if (peerRef.current && remoteDescSetRef.current) {
        peerRef.current.addIceCandidate(new RTCIceCandidate(data.candidate)).catch(() => {});
      } else {
        pendingIceCandidatesRef.current.push(data.candidate);
      }
    }
  };

  const flushIceCandidates = () => {
    if (!peerRef.current) return;
    pendingIceCandidatesRef.current.forEach(c => {
      peerRef.current.addIceCandidate(new RTCIceCandidate(c)).catch(() => {});
    });
    pendingIceCandidatesRef.current = [];
  };

  const acceptCall = async () => {
    if (!callOffer) return;
    try {
      remoteDescSetRef.current = false;
      pendingIceCandidatesRef.current = [];
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' },
        ]
      });
      peerRef.current = pc;
      stream.getTracks().forEach(t => pc.addTrack(t, stream));
      pc.ontrack = (e) => {
        if (remoteAudioRef.current) {
          remoteAudioRef.current.srcObject = e.streams[0];
          remoteAudioRef.current.play().catch(() => {});
        }
      };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN)
          wsRef.current.send(JSON.stringify({ type: 'webrtc_ice', candidate: e.candidate }));
      };
      await pc.setRemoteDescription(new RTCSessionDescription(callOffer.sdp));
      remoteDescSetRef.current = true;
      flushIceCandidates();
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);
      if (wsRef.current?.readyState === WebSocket.OPEN)
        wsRef.current.send(JSON.stringify({ type: 'webrtc_answer', sdp: answer }));
      setInCall(true); setIncomingCall(false); setCallOffer(null);
      setCallDuration(0);
      callTimerRef.current = setInterval(() => setCallDuration(prev => prev + 1), 1000);
    } catch (err) { console.error('Erro ao atender chamada:', err); setIncomingCall(false); setCallOffer(null); }
  };

  const rejectCall = () => { setIncomingCall(false); setCallOffer(null); };

  const endCall = () => {
    peerRef.current?.close(); peerRef.current = null;
    localStreamRef.current?.getTracks().forEach(t => t.stop()); localStreamRef.current = null;
    remoteDescSetRef.current = false;
    pendingIceCandidatesRef.current = [];
    clearInterval(callTimerRef.current);
    setInCall(false); setCallDuration(0);
  };

  useEffect(() => { return () => { wsRef.current?.close(); endCall(); }; }, []);

  // ── Render message content ──
  const renderMsgContent = (m) => {
    const extra = m.extra;
    const isDark = m.remetente === 'cliente';
    if (extra?.tipo === 'audio') {
      return <AudioPlayer src={`/api/chat/audio/${extra.arquivo}`} dark={isDark} />;
    }
    if (extra?.tipo === 'imagem') {
      return <img src={`/api/chat/imagem/${extra.arquivo}`} alt="Imagem" className="rounded-lg max-w-full max-h-40 cursor-pointer" onClick={() => window.open(`/api/chat/imagem/${extra.arquivo}`, '_blank')} />;
    }
    if (extra?.tipo === 'gravacao') {
      return <p className="text-xs">📎 Gravação de chamada</p>;
    }
    return <p className="whitespace-pre-wrap">{m.mensagem}</p>;
  };

  return (
    <>
      <audio ref={remoteAudioRef} autoPlay playsInline style={{ display: 'none' }} />
      <input type="file" ref={imageInputRef} accept="image/*" style={{ display: 'none' }} onChange={handleImageUpload} />

      {!open && (
        <button onClick={() => { setOpen(true); setUnread(0); }} className="fixed bottom-6 right-6 z-50 bg-gradient-to-r from-purple-600 to-indigo-600 text-white rounded-full p-4 shadow-2xl hover:scale-110 transition-transform">
          <Icon name="chat" size={24} />
          {unread > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center font-bold">{unread}</span>}
        </button>
      )}

      {open && (
        <div className="fixed bottom-6 right-6 z-50 w-[380px] h-[560px] bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden border border-gray-200">
          {/* Header */}
          <div className="bg-gradient-to-r from-purple-600 to-indigo-600 text-white p-4 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Icon name="chat" size={20} />
              <div>
                <p className="text-sm font-bold">Suporte ao Vivo</p>
                {protocolo && <p className="text-[10px] text-purple-200">{protocolo}</p>}
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button onClick={() => setOpen(false)} className="p-1 hover:bg-white/20 rounded"><Icon name="x" size={20} /></button>
            </div>
          </div>

          <div className="flex-1 flex flex-col overflow-hidden">
            {/* Login Form */}
            {view === 'form' && (
              <div className="flex-1 flex flex-col items-center justify-center p-6">
                <Icon name="user" size={48} />
                <h3 className="text-lg font-bold text-gray-800 mb-1 mt-3">Bem-vindo ao Chat</h3>
                <p className="text-xs text-gray-500 mb-4 text-center">Faça login ou crie uma conta para iniciar</p>
                {error && <div className="w-full bg-red-50 border border-red-200 text-red-600 text-xs px-3 py-2 rounded-lg mb-3">{error}</div>}
                <form onSubmit={handleLogin} className="w-full space-y-2">
                  <input type="email" placeholder="E-mail" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="password" placeholder="Senha" value={formData.senha} onChange={(e) => setFormData({ ...formData, senha: e.target.value })} required minLength={4} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <button type="submit" disabled={loading} className="w-full bg-purple-600 text-white font-medium py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 text-sm">{loading ? 'Entrando...' : 'Entrar'}</button>
                </form>
                <div className="my-3 flex items-center gap-2 w-full"><div className="flex-1 h-px bg-gray-200" /><span className="text-xs text-gray-400">ou</span><div className="flex-1 h-px bg-gray-200" /></div>
                <button onClick={() => { setView('register'); setError(''); }} className="w-full border border-purple-300 text-purple-700 font-medium py-2 rounded-lg hover:bg-purple-50 text-sm">Criar Conta</button>
              </div>
            )}

            {/* Register Form */}
            {view === 'register' && (
              <div className="flex-1 flex flex-col p-6 overflow-y-auto">
                <h3 className="text-lg font-bold text-gray-800 mb-1">Criar Conta</h3>
                <p className="text-xs text-gray-500 mb-4">Preencha seus dados</p>
                {error && <div className="w-full bg-red-50 border border-red-200 text-red-600 text-xs px-3 py-2 rounded-lg mb-3">{error}</div>}
                <form onSubmit={handleSendVerification} className="space-y-2">
                  <input type="text" placeholder="Nome completo" value={formData.nome} onChange={(e) => setFormData({ ...formData, nome: e.target.value })} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="email" placeholder="E-mail" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="tel" placeholder="Telefone" value={formData.telefone} onChange={(e) => setFormData({ ...formData, telefone: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="password" placeholder="Senha" value={formData.senha} onChange={(e) => setFormData({ ...formData, senha: e.target.value })} required minLength={4} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <button type="submit" disabled={loading} className="w-full bg-purple-600 text-white font-medium py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 text-sm">{loading ? 'Enviando...' : 'Enviar Código de Verificação'}</button>
                </form>
                <button onClick={() => { setView('form'); setError(''); }} className="mt-3 text-sm text-purple-600 hover:underline text-center">Voltar ao login</button>
              </div>
            )}

            {/* Verification */}
            {view === 'verify' && (
              <div className="flex-1 flex flex-col p-6 overflow-y-auto">
                <h3 className="text-lg font-bold text-gray-800 mb-1">Verificação</h3>
                <p className="text-xs text-gray-500 mb-4">Código de 6 dígitos enviado para {formData.email}</p>
                {error && <div className="w-full bg-red-50 border border-red-200 text-red-600 text-xs px-3 py-2 rounded-lg mb-3">{error}</div>}
                <form onSubmit={handleRegister} className="space-y-3">
                  <input type="text" placeholder="000000" value={verificationCode} onChange={(e) => setVerificationCode(e.target.value.replace(/\D/g, '').slice(0, 6))} required maxLength={6} className="w-full px-3 py-3 border border-gray-300 rounded-lg text-center text-2xl font-bold tracking-widest focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-3 text-xs text-yellow-800">
                    <p className="font-semibold mb-1">Não recebeu?</p><p>Verifique spam/lixo eletrônico.</p>
                  </div>
                  <button type="submit" disabled={loading || verificationCode.length !== 6} className="w-full bg-purple-600 text-white font-medium py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 text-sm">{loading ? 'Verificando...' : 'Criar Conta'}</button>
                  <button type="button" onClick={handleResendCode} disabled={loading} className="w-full border border-purple-300 text-purple-700 font-medium py-2 rounded-lg hover:bg-purple-50 disabled:opacity-50 text-sm">Reenviar Código</button>
                </form>
                <button onClick={() => { setView('register'); setError(''); setVerificationCode(''); }} className="mt-3 text-sm text-purple-600 hover:underline text-center">Voltar</button>
              </div>
            )}

            {/* Chat */}
            {view === 'chat' && (
              <>
                {protocolo && (
                  <div className="px-4 py-1.5 bg-purple-50 border-b border-purple-100 flex items-center justify-between">
                    <span className="text-[11px] text-purple-700 font-medium">Protocolo: {protocolo}</span>
                    {inCall && (
                      <span className="flex items-center gap-1 text-[11px] text-red-600 font-medium animate-pulse">
                        <Icon name="phone" size={12} /> Em chamada {formatTime(callDuration)}
                      </span>
                    )}
                  </div>
                )}

                {/* In-call overlay bar */}
                {inCall && (
                  <div className="bg-gradient-to-r from-green-500 to-emerald-600 text-white px-4 py-2 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <div className="w-2 h-2 bg-white rounded-full animate-pulse" />
                      <span className="text-sm font-medium">Chamada em andamento - {formatTime(callDuration)}</span>
                    </div>
                    <button onClick={endCall} className="p-1.5 bg-red-500 rounded-full hover:bg-red-600">
                      <Icon name="phoneOff" size={14} />
                    </button>
                  </div>
                )}

                <div className="flex-1 overflow-y-auto p-3 space-y-2 bg-gray-50">
                  {mensagens.map((m, idx) => (
                    <div key={idx} className={`flex ${m.remetente === 'cliente' ? 'justify-end' : m.remetente === 'sistema' ? 'justify-center' : 'justify-start'}`}>
                      {m.remetente === 'sistema' ? (
                        <div className="bg-yellow-100 text-yellow-800 text-[11px] px-3 py-1 rounded-full max-w-[85%] text-center">
                          <Icon name="shield" size={12} /> {m.mensagem}
                        </div>
                      ) : (
                        <div className={`max-w-[75%] px-3 py-2 rounded-2xl text-sm ${m.remetente === 'cliente' ? 'bg-purple-600 text-white rounded-br-md' : 'bg-white text-gray-900 shadow rounded-bl-md'}`}>
                          {renderMsgContent(m)}
                          <div className={`flex items-center justify-end gap-0.5 mt-0.5 ${m.remetente === 'cliente' ? 'text-purple-200' : 'text-gray-400'}`}>
                            {m.data_criacao && (
                              <span className="text-[9px]">
                                {new Date(m.data_criacao).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                              </span>
                            )}
                            {m.remetente === 'cliente' && <SeenIndicator sent={m.lida} />}
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                  <div ref={messagesEndRef} />
                </div>

                {/* Input area */}
                {isRecordingAudio ? (
                  <div className="p-3 border-t border-gray-200 bg-red-50">
                    <div className="flex items-center gap-2">
                      <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
                      <span className="text-sm text-red-700 font-medium flex-1">Gravando... {formatTime(recordingTime)}</span>
                      <button onClick={cancelAudioRecording} className="p-2 bg-gray-200 rounded-full hover:bg-gray-300 text-gray-600" title="Cancelar">
                        <Icon name="x" size={16} />
                      </button>
                      <button onClick={sendAudioRecording} className="p-2 bg-purple-600 rounded-full hover:bg-purple-700 text-white" title="Enviar">
                        <Icon name="send" size={16} />
                      </button>
                    </div>
                  </div>
                ) : (
                  <form onSubmit={handleEnviar} className="p-3 border-t border-gray-200 bg-white">
                    <div className="flex gap-1.5 items-center">
                      <button type="button" onClick={() => imageInputRef.current?.click()} className="p-2 text-gray-400 hover:text-purple-600 hover:bg-purple-50 rounded-full" title="Enviar imagem">
                        <Icon name="image" size={18} />
                      </button>
                      <button type="button" onClick={startAudioRecording} className="p-2 text-gray-400 hover:text-purple-600 hover:bg-purple-50 rounded-full" title="Gravar áudio">
                        <Icon name="mic" size={18} />
                      </button>
                      <input type="text" value={novaMensagem} onChange={(e) => setNovaMensagem(e.target.value)} placeholder="Digite sua mensagem..." className="flex-1 px-3 py-2 border border-gray-300 rounded-full text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                      <button type="submit" disabled={!novaMensagem.trim()} className="bg-purple-600 text-white p-2 rounded-full hover:bg-purple-700 disabled:opacity-50">
                        <Icon name="send" size={16} />
                      </button>
                    </div>
                  </form>
                )}
              </>
            )}
          </div>
        </div>
      )}

      {/* Incoming Call - Fullscreen phone-call style */}
      {incomingCall && (
        <div className="fixed inset-0 z-[60] flex flex-col items-center justify-center bg-gradient-to-b from-gray-900 to-gray-800">
          <div className="flex flex-col items-center">
            <div className="w-24 h-24 bg-gray-700 rounded-full flex items-center justify-center mb-6">
              <Icon name="user" size={48} />
            </div>
            <h2 className="text-white text-2xl font-bold mb-1">Atendente</h2>
            <p className="text-gray-400 text-sm mb-2">Chamada de voz recebida</p>
            <div className="flex items-center gap-1 text-green-400 animate-pulse mb-12">
              <div className="w-2 h-2 bg-green-400 rounded-full" />
              <span className="text-sm">Chamando...</span>
            </div>
          </div>
          <div className="flex gap-16">
            <div className="flex flex-col items-center gap-2">
              <button onClick={rejectCall} className="w-16 h-16 bg-red-500 rounded-full flex items-center justify-center hover:bg-red-600 shadow-lg shadow-red-500/30">
                <Icon name="phoneOff" size={28} />
              </button>
              <span className="text-gray-400 text-xs">Recusar</span>
            </div>
            <div className="flex flex-col items-center gap-2">
              <button onClick={acceptCall} className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center hover:bg-green-600 shadow-lg shadow-green-500/30 animate-bounce">
                <Icon name="phone" size={28} />
              </button>
              <span className="text-gray-400 text-xs">Atender</span>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatWidget;
